const mapFunction = (inputData) => {
    const checkIfFileExists = (filePaths, filePath)=>{
        for(let i = 0; i < filePaths.length; i++){
            if(filePaths[i].startsWith(filePath)){
                return true;
            }
        }

        return false;
    } 

    const nodes = [];
    const edges = [];

    const files = inputData;
    const filePaths = files.map(file => file.filePath);

    for(let i = 0; i < files.length; i++) {
      const currentFile = files[i];
      const filePath = currentFile.filePath;
      
      const data = {
        id: filePath,
        label : filePath,
        description: currentFile.description,
        filePath: filePath,
        exports: currentFile.exports,
        imports: currentFile.imports,
        size: Math.max(20, Math.min(50, currentFile.exports.length * 10))
      }

      nodes.push({ data });

    //   console.log(filePath, ":", currentFile.imports)

      for(let j = 0; j < currentFile.imports.length; j++) {
        const importTarget = currentFile.imports[j];

        const importSplitted = importTarget.split('.');

        const edgeLabel = importSplitted[importSplitted.length - 1];
        importSplitted.pop();
        const importFilePath = importSplitted.join('.');
        // console.log(checkIfFileExists(filePaths, importFilePath));

        // if(filePaths.includes(importFilePath)){
        if(checkIfFileExists(filePaths, importFilePath) && importFilePath){
          const _data = {
            id : `${filePath}-imports-${importFilePath}`,
            label : edgeLabel,
            source : filePath,
            target : importFilePath,
            type : 'imports',
            importedProperty: edgeLabel
          }
          edges.push({ data: _data });
        }
      }
    }

    console.log(edges);

    return {
      elements: {
        nodes,
        edges
      }
    }
  }

