    "content": "import 'jest';\nimport app from '../src/app';\nimport request from 'supertest';\nimport { Prompt } from '../src/models/Prompt';\nimport { sequelize } from '../src/config/database';\n\nbeforeAll(async ()=>{\n    await sequelize.sync({ force : true });\n})\n\nafterAll(async ()=>{\n    await sequelize.close();\n})\n\ndescribe('POST /prompt/', ()=>{\n    it(\"Should return 200\", async ()=>{\n        let response = await request(app)\n        .post('/prompt/')\n        .send({\n            prompt : \"Hello World\",\n            options : [\"Hello\"]\n        });\n\n        expect(response.statusCode).toBe(200)\n    })\n\n    it(\"Should record prompt\", async ()=>{\n        let last = await Prompt.findOne({ order : [['id', 'desc']] });\n        let lastId : number;\n\n        if(!last){\n            lastId = 0\n        }else{\n            lastId = Number(last.dataValues.id);\n        }\n\n        await request(app)\n        .post('/prompt/')\n        .send({\n            prompt : \"Hello World\",\n            options : [\"Hello\"]\n        });\n\n        console.log(lastId)\n\n        let newLastId : any = (await Prompt.findOne({ order : [['id', 'desc']] }))?.dataValues.id;\n\n        console.log(newLastId);\n\n        expect(newLastId).toBe(lastId + 1);\n    })\n\n    it(\"Should return JSON\", async ()=>{\n        let response = await request(app)\n        .post('/prompt/')\n        .send({\n            prompt : \"Hello World\",\n            options : [\"World\"]\n        });\n\n        expect(response.headers[\"content-type\"]).toContain(\"application/json\");\n    })\n\n    it(\"Should return prompt response\", async ()=>{\n        let response = await request(app)\n        .post('/prompt/')\n        .send({\n            prompt : \"What color of cap should I wear to Christmas eve?\",\n            options : [\"Red\", \"Green\", \"White\", \"Yellow\"]\n        });\n\n        expect(response.body.body.prompt.response).toBeDefined()\n    })\n\n    it(\"Should return 400\", async ()=>{\n        let response = await request(app)\n        .post('/prompt/')\n        .send({\n            promp : \"Hello World\",\n            options : [\"World\"]\n        });\n\n        expect(response.statusCode).toBe(400);\n    })\n})",
