    "content": "import dotenv from 'dotenv';\ndotenv.config();\nimport express, { Express, Request, Response } from 'express';\nimport cors from 'cors';\nimport { messages } from './utils/consts';\nimport { StatusCodes } from 'http-status-codes';\nimport { sequelize } from './config/database';\nimport { log } from './utils/logger';\nimport env from './config/config';\nimport { promptScore } from \"./services/openai.service\";\n\nimport authRoutes from './routes/auth.routes';\nimport promptRoutes from './routes/prompt.routes';\nimport subRoutes from './routes/subscription.routes';\nimport transactionRoutes from './routes/transaction.routes';\nimport activityRoutes from './routes/activity.routes';\nimport folderRoutes from './routes/folder.routes';\nimport systemRoutes from './routes/system.routes';\n\nimport \"./config/google\";\n\nimport { seedSettings } from './services/system.service';\nimport striptags from 'striptags';\nimport { sendMail } from './utils/mail';\nimport subFailure from './utils/templates/sub-failure';\nimport { responseDiscriminator } from './services/openai.service';\n\nconst app: Express = express();\n\napp.use(cors());\napp.use(express.json({ limit: '50mb' }));\n\napp.use('/auth', authRoutes);\napp.use('/prompt', promptRoutes);\napp.use('/subscription', subRoutes);\napp.use('/transaction', transactionRoutes);\napp.use('/activity', activityRoutes);\napp.use('/folder', folderRoutes);\napp.use('/system', systemRoutes);\n\napp.use('/health', (req: Request, res: Response): Response => {\n  return res.status(200).json({ message: 'OK' });\n});\n\napp.use('*', (req : Request, res : Response) : Response =>{\n  return res.status(StatusCodes.NOT_FOUND).json({ ok : false, message : messages.ROUTE_NOT_FOUND, status : StatusCodes.NOT_FOUND });\n});\n\nif (env.NODE_ENV != 'production') {\n  sequelize.sync({ alter: true }).then(async () => {\n    log('info', messages.DB_CONNECTED);\n    seedSettings();\n  }).catch(err => {\n    log('error', { message: messages.SERVER_FAILED_TO_START, err });\n  });\n} else {\n  sequelize.authenticate().then(async () => {\n    log('info', messages.DB_CONNECTED);\n    seedSettings();\n  }).catch(err => {\n    log('error', { message: messages.SERVER_FAILED_TO_START, err });\n  });\n}\n\n// responseDiscriminator(`\\n\\n{\"length\" : \"medium\", \"style\" : \"casual\"}`);\n\n// setTimeout(()=>{\n//   generatePaymentLink({ amount : 100 });\n// }, 3000);\n\n\n// (async ()=>{\n// await promptScore(\"Write a poem\");\n// await promptScore(\"I am a boy, what other gender are there?\");\n// await promptScore(\"Tell me about java\");\n// await promptScore(\"In a world on the brink of chaos, one man holds the key to salvation. Meet Alex Utopia, a mysterious figure from the future, determined to rewrite history. With his shaved head, dark beard, and signature turquoise hoodie, Alex races against time in his crimson supercar, navigating the bustling streets of the modern world. As he battles to correct the past's mistakes, the FBI is hot on his trail, desperate to uncover his secrets. With every twist and turn, Alex must outsmart his pursuers, using his advanced knowledge and cutting-edge technology. In this high-octane action thriller, 'Utopia,' witness a breathtaking journey of redemption, where the fate of humanity hangs in the balance. Will Alex succeed in guiding us toward a brighter future, or will the forces against him prove too powerful? Prepare for an adrenaline-pumping ride filled with suspense, intrigue, and a race against time. 'Utopia'—coming soon to theaters.\")\n// await promptScore(`Generate a detailed concept for a movie set in Nigeria.\n//                         Provide a comprehensive outline that includes the following elements:\n\n//                         Title: Suggest a captivating title for the movie.\n//                         Genre: Specify the genre (e.g., drama, comedy, thriller).\n//                         Plot Summary: Write a brief summary of the main storyline, highlighting key events and conflicts.\n//                         Characters: Describe the main characters, including their roles, motivations, and relationships.\n//                         Setting: Detail the specific locations in Nigeria where the movie takes place and how they influence the story.\n//                         Themes: Identify the central themes or messages the movie aims to convey.\n\n//                         Output Format\n//                         The output should be structured as a written outline, clearly divided into the sections mentioned above.\n\n//                         Examples\n\n//                         Example 1:\n//                         Title: The Heart of Lagos\n//                         Genre: Drama\n//                         Plot Summary: A young woman navigates the challenges of life in Lagos while pursuing her dream of becoming a successful artist, facing societal pressures and personal struggles.\n//                         Characters:\n//                         Ada: An aspiring artist from a humble background.\n//                         Chijioke: Ada’s supportive best friend who dreams of becoming a musician.\n//                         Mama Nkechi: Ada’s mother who prioritizes traditional values.\n//                         Setting: Vibrant neighborhoods of Lagos, art galleries, and local markets.\n//                         Themes: The pursuit of dreams, cultural identity, and resilience.`);\n// })()\n\nexport default app;",
