    "content": "import { Sequelize } from \"sequelize-typescript\";\nimport { User } from '../models/User';\nimport { Prompt } from '../models/Prompt';\nimport { Otp } from '../models/Otp';\nimport { Subscription } from '../models/Subscription';\nimport { Transaction } from '../models/Transaction';  \nimport { ApiKey } from '../models/ApiKey';\nimport { Activity } from '../models/Activity';\nimport { Folder } from \"../models/Folder\";\nimport { SystemSetting } from \"../models/SystemSetting\";\nimport env from './config';\n\nexport const sequelize = new Sequelize({\n    dialect: 'mysql',\n    host : env.DB_HOST,\n    port : parseInt(`${env.DB_PORT}`),\n    username : env.DB_USER,\n    password : env.DB_PASSWORD,\n    database : env.DB_NAME,\n    // logging : false\n});\n\nsequelize.addModels([\n    User,\n    Prompt,\n    Otp,\n    Subscription,\n    Transaction,\n    ApiKey,\n    Activity,\n    Folder,\n    SystemSetting\n]);\n\nUser.hasMany(Prompt, { foreignKey: 'user_id', as: 'prompts' });\nPrompt.belongsTo(User, { foreignKey: 'user_id', as: 'user', constraints: false });\n\nUser.hasMany(Otp, { foreignKey : \"user_id\", as : \"otps\" });\nOtp.belongsTo(User, { foreignKey : \"user_id\", as : \"user\" });\n\nUser.hasMany(Subscription, { foreignKey: 'user_id', as: 'subscriptions' });\nSubscription.belongsTo(User, { foreignKey: 'user_id', as: 'user' });\n\nUser.hasMany(Transaction, { foreignKey: 'user_id', as: 'transactions' });\nTransaction.belongsTo(User, { foreignKey: 'user_id', as: 'user' });\n\nSubscription.hasMany(Transaction, { foreignKey : \"subscription_id\", as : \"transactions\" });\nTransaction.belongsTo(Subscription, { foreignKey : \"subscription_id\", as : \"subscription\" });\n\nUser.hasMany(ApiKey, { foreignKey : \"user_id\", as : \"api_keys\" })\nApiKey.belongsTo(User, { foreignKey : \"user_id\", as : \"user\" });\n\nUser.hasMany(Activity, { foreignKey : \"user_id\", as : \"activities\" })\nActivity.belongsTo(User, { foreignKey : \"user_id\", as : \"user\" });\n\nUser.hasMany(Folder, { foreignKey : \"user_id\", as : \"folders\" });\nFolder.belongsTo(User, { foreignKey : \"user_id\", as : \"user\" });\n\nFolder.hasMany(Folder, { foreignKey : { name: \"parent_id\", allowNull: true }, as : \"subfolders\" });\nFolder.belongsTo(Folder, { foreignKey: { name: \"parent_id\", allowNull: true }, as: \"parent\" });\n\nFolder.hasMany(Prompt, { foreignKey : { name : \"folder_id\", allowNull : true }, as : \"prompts\" });\nPrompt.belongsTo(Folder, { foreignKey : { name : \"folder_id\", allowNull : true }, as : \"folder\" });",
    "exports": [
      "sequelize"
    ],
