    "content": "import { Request, Response } from \"express\";\nimport { listWithPaginationValidation } from \"../utils/validations/prompt.validation\";\n\nimport { log } from \"../utils/logger\";\nimport { User } from \"../models/User\";\nimport { listActivitiesService } from \"../services/activity.service\";\n\nexport default {\n    listActivities : async (req : Request & { user : User }, res : Response) : Promise<Response> =>{\n        const { url, query, user, ip } = req;\n\n        try{\n            let payload = listWithPaginationValidation(query);\n            let service = await listActivitiesService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    }\n}",
