    "content": "import { Request, Response } from 'express';\nimport { log } from '../utils/logger';\nimport {\n    signupValidation,\n    verifyOtpValidation,\n    loginValidation,\n    updateUserDetailsValidation,\n    generateApiKeyValidation\n} from '../utils/validations/auth.validation';\nimport {\n    signupService,\n    verifyOtpService,\n    resendOtpService,\n    loginService,\n    updateUserDetailsService,\n    generateApiKeyService,\n    getUserService,\n    refreshTokenService\n} from '../services/auth.service';\nimport { User } from '../models/User';\n\nexport default {\n    refreshToken: async (req: Request | any, res: Response): Promise<any> => {\n        const { ip, url, user } = req;\n\n        try {\n            let service = await refreshTokenService(user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    getUser: async (req: Request | any, res: Response): Promise<Response> => {\n        const { ip, url, user } = req;\n\n        try {\n            let service = await getUserService(user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            console.log(error);\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    signup: async (req: Request | any, res: Response): Promise<Response> => {\n        const { body, ip, url } = req;\n\n        try {\n            let payload = signupValidation(body);\n            let service = await signupService(payload);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    login: async (req: Request | any, res: Response): Promise<Response> => {\n        const { body, ip, url } = req;\n\n        try {\n            let payload = loginValidation(body);\n            let service = await loginService(payload);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    verifyOtp: async (req: Request & { user: User }, res: Response): Promise<Response> => {\n        const { body, ip, url, user } = req;\n\n        try {\n            let payload = verifyOtpValidation(body);\n            let service = await verifyOtpService(payload, user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    resendOtp: async (req: Request & { user: User }, res: Response): Promise<Response> => {\n        const { ip, url, user } = req;\n\n        try {\n            let service = await resendOtpService(user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    updateUserDetails: async (req: Request & { user: User }, res: Response): Promise<Response> => {\n        const { body, ip, url, user } = req;\n\n        try {\n            let payload = updateUserDetailsValidation(body);\n            let service = await updateUserDetailsService(payload, user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    generateApiKey: async (req: Request & { user: User }, res: Response): Promise<Response> => {\n        const { body, ip, url, user } = req;\n\n        try {\n            let payload = generateApiKeyValidation(body);\n            let service = await generateApiKeyService(payload, user);\n            return res.status(service.status).json({ ...service });\n        } catch (error: any) {\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    }\n}",
