    "content": "import { Request, Response } from \"express\";\nimport { createFolderValidation, editFolderValidation, listFoldersValidation } from \"../utils/validations/folder.validation\";\nimport { log } from \"../utils/logger\";\nimport { User } from \"../models/User\";\nimport { createFolderService, editFolderService, deleteFolderService, listFoldersService } from \"../services/folder.service\";\nimport { singleIdValidation } from \"../utils/validations/prompt.validation\";\n\nexport default {\n    createFolder : async (req : Request & { user : User }, res : Response) : Promise<Response> =>{\n        const { url, body, user, ip } = req;\n\n        try{\n            let payload = createFolderValidation(body);\n            let service = await createFolderService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    editFolder : async (req : Request & { user : User }, res : Response) : Promise<Response> =>{\n        const { url, body, user, ip, params } = req;\n\n        try{\n            let payload = editFolderValidation({...body, ...params});\n            let service = await editFolderService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    deleteFolder : async (req : Request & { user : User }, res : Response) : Promise<Response> =>{\n        const { url, user, ip, params } = req;\n\n        try{\n            let payload = singleIdValidation(params);\n            let service = await deleteFolderService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    },\n    listFolders : async (req : Request & { user : User }, res : Response) : Promise<Response> =>{\n        const { url, query, user, ip } = req;\n\n        try{\n            let payload = listFoldersValidation(query);\n            let service = await listFoldersService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({ ...error });\n        }\n    }\n}",
