    "content": "import { Request, Response } from \"express\";\nimport { promptValidation, listWithPaginationValidation, singleIdValidation, savePromptValidation, listPromptsValidation } from \"../utils/validations/prompt.validation\";\nimport { promptService, listPromptsService, getPromptService, savePromptService } from '../services/prompt.service';\nimport { log } from \"../utils/logger\";\nimport { User } from \"../models/User\";\n\nexport default {\n    prompt : async (req : any, res : Response) : Promise<Response> =>{\n        const { url, body, user } = req;\n\n        const ip = Array.isArray(req.headers['x-forwarded-for']) \n            ? req.headers['x-forwarded-for'][0] \n            : req.headers['x-forwarded-for'] || req.socket.remoteAddress as string;\n        const userAgent = req.headers['user-agent'] || \"unknown\";\n\n        try{\n            let payload = promptValidation({...body, ip, user_agent : userAgent});\n            let service = await promptService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            console.log(error);\n            log('error', { error, ip, url });\n            return res.status(error.status).json({...error});\n        }\n    },\n    list : async (req : any, res : Response) : Promise<Response> =>{\n        const { user, query, url, ip } = req;\n\n        try{\n            let payload = listPromptsValidation(query);\n            let service = await listPromptsService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({...error});\n        }\n    },\n    get : async (req : any, res : Response) : Promise<Response> =>{\n        const { user, params, url, ip } = req;\n\n        try{\n            let payload = singleIdValidation(params);\n            let service = await getPromptService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({...error});\n        }\n    },\n    save : async (req : any, res : Response) : Promise<Response> =>{\n        const { user, body, url, ip } = req;\n\n        try{\n            let payload = savePromptValidation(body);\n            let service = await savePromptService(payload, user);\n            return res.status(service.status).json({...service});\n        }catch(error : any){\n            log('error', { error, ip, url });\n            return res.status(error.status).json({...error});\n        }\n    }\n}",
