    "content": "import { Response, NextFunction } from 'express';\nimport { StatusCodes } from 'http-status-codes';\nimport { User } from '../models/User';\nimport { messages } from '../utils/consts';\nimport { log } from '../utils/logger';\nimport { compareString, extractSignature } from '../utils/auth';\nimport { ApiKey } from '../models/ApiKey';\n\n\nconst verifyUserIfAvailableInner = async (req : any) : Promise<number | any> =>{\n    let headers = req.headers;\n    let authToken = headers.authorization;\n\n    if(!authToken){\n        return null;\n    }\n\n    authToken = authToken.replace('Bearer ', '');\n    let user : User | null;\n\n    try{\n        let verifiedObject = extractSignature(authToken);\n        user = (await User.findOne({ where : { id : verifiedObject.user_id } }))?.dataValues;\n    }catch(error : any){\n        log('error', error);\n        return StatusCodes.FORBIDDEN;\n    }\n\n    if(!user){\n        return StatusCodes.FORBIDDEN;\n    }\n\n    if(!user.email_verified){\n        return StatusCodes.FORBIDDEN;\n    }\n\n    return user;\n}\n\nexport const verifyUserIfAvailable = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let check = await verifyUserIfAvailableInner(req);\n\n    if(typeof(check) == \"number\"){\n        let message = check == StatusCodes.FORBIDDEN ? messages.FORBIDDEN : messages.FORBIDDEN;\n        return res.status(check).json({ ok : false, message, status : check })\n    }\n    req[\"user\"] = check;\n    next();\n}\n\nconst verifyUserInner = async (req : any) : Promise<number | any> =>{\n    let headers = req.headers;\n    let authToken = headers.authorization;\n\n    if(!authToken){\n        return StatusCodes.FORBIDDEN\n    }\n\n    authToken = authToken.replace('Bearer ', '');\n    let user : User | null;\n\n    try{\n        let verifiedObject = extractSignature(authToken);\n        user = (await User.findOne({ where : { id : verifiedObject.user_id } }))?.dataValues;\n    }catch(error : any){\n        log('error', error);\n        return StatusCodes.FORBIDDEN\n    }\n\n    if(!user){\n        return StatusCodes.FORBIDDEN;\n    }\n\n    if(!user.email_verified){\n        return StatusCodes.FORBIDDEN;\n    }\n\n    return user;\n}\n\nexport const verifyUser = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let check = await verifyUserInner(req);\n\n    if(typeof(check) == \"number\"){\n        let message = check == StatusCodes.FORBIDDEN ? messages.FORBIDDEN : messages.FORBIDDEN;\n        return res.status(check).json({ ok : false, message, status : check })\n    }\n    req[\"user\"] = check;\n    next();\n}\n\nexport const verifyUnverifiedUser = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let headers = req.headers;\n    let authToken = headers.authorization;\n\n    if(!authToken){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    authToken = authToken.replace('Bearer ', '');\n    let user : User | null;\n\n    try{\n        let verifiedObject = extractSignature(authToken);\n        user = await User.findOne({ where : { id : verifiedObject.user_id } });\n    }catch(error : any){\n        log('error', error);\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN })\n    }\n\n    if(!user){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    if(user.email_verified){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    req['user'] = user;\n    next();\n}\n\nexport const verifyApiKey = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let headers = req.headers;\n    let authToken = headers.authorization;\n    let user_id = headers.user_id;\n\n    if(!authToken || !user_id){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    let api_key = await ApiKey.findOne({ where : { user_id }, order : [[\"id\", \"desc\"]] });\n\n    if(!api_key || !api_key?.is_active){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    authToken = authToken.replace('Bearer ', '');\n    let user : User | null;\n    let check = compareString(authToken, api_key.key);\n\n    if(!check){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    user = await User.findOne({ where : { id : user_id } });\n\n    if(!user){\n        return res.status(StatusCodes.FORBIDDEN).json({ ok : false, message : messages.FORBIDDEN, status : StatusCodes.FORBIDDEN });\n    }\n\n    await ApiKey.update({ hits : Number(api_key.hits) + 1 }, { where : { id : api_key.id } });\n    req.user = user;\n    next();\n}\n\nexport const normalOrApiKeyIfAvailable = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let response = await verifyUserIfAvailableInner(req);\n\n    if(typeof(response) != \"number\"){\n        req[\"user\"] = response;\n        next();\n        return;\n    }\n\n    if(response == null){\n        next();\n        return;\n    }\n\n    if(response !== undefined){\n        return await verifyApiKey(req, res, next);\n    }\n}\n\nexport const normalOrApiKey = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> =>{\n    let response = await verifyUserInner(req);\n    \n    if(typeof(response) != \"number\"){\n        req[\"user\"] = response;\n        next();\n        return;\n    }\n\n    if(response !== undefined){\n        return await verifyApiKey(req, res, next);\n    }\n}",
    "exports": [
      "verifyUserIfAvailable",
      "verifyUser",
      "verifyUnverifiedUser",
      "verifyApiKey",
      "normalOrApiKeyIfAvailable",
      "normalOrApiKey"
    ],
