    "content": "import { NextFunction, Response } from \"express\";\nimport { createOrLoginUserFromGoogleService } from \"../services/auth.service\";\nimport env from \"../config/config\";\n\nexport const googleAuthCallbackMiddleware = async (req : any, res : Response, next : NextFunction) : Promise<Response | void> => {\n    let token = await createOrLoginUserFromGoogleService(req.user);\n    let state = req.query.state ? JSON.parse(req.query.state) : {};\n    let keys = Object.keys(state);\n    let dynamicQs = \"\";\n\n    for(let i = 0; i < keys.length; i++){\n        dynamicQs += `&${keys[i]}=${state[keys[i]]}`;\n    }\n\n    return res.redirect(`${env.FRONTEND_LOGIN_URL}?token=${token}${dynamicQs}`);\n}",
    "exports": [
      "googleAuthCallbackMiddleware"
    ],
