    "content": "import { Response, NextFunction } from 'express';\n\nexport const normalizeFileContext = async (req : any, res : Response, next : NextFunction) : Promise<void | Response> =>{\n    if(req.body.file_context){\n        let file_context = req.body.file_context;\n\n        if(typeof(file_context) == \"string\"){\n            req.body.file_context = [file_context];\n        }\n    }\n\n    next();\n}",
