    "content": "import { Response, NextFunction } from 'express';\nimport { messages, plans, subscription_payment_statuses } from '../utils/consts';\nimport { rateLimit } from 'express-rate-limit';\nimport { Subscription } from '../models/Subscription';\nimport { Op } from 'sequelize';\nimport { Prompt } from '../models/Prompt';\nimport { StatusCodes } from 'http-status-codes';\n\n\nexport const generatorRateLimit = rateLimit({\n    windowMs: 24 * 60 * 60 * 1000,\n    // 100 for dev pupose, whould be 10 standardly\n    max: 5,\n    message: 'Too many requests, please try again later.'\n});\n\nexport const getRateLimitersBySubscription = async (plan: string): Promise<Array<any>> => {\n    let _plans = await plans()\n    let planData = _plans[plan];\n\n    let rateLimiterMinute = rateLimit({\n        windowMs: 60 * 60 * 1000,\n        max: planData.request_per_minute,\n        message: 'Too many requests, please upgrade your plan.'\n    });\n\n    let rateLimiterMonth = rateLimit({\n        windowMs: 30 * 24 * 60 * 60 * 1000,\n        max: planData.request_per_month,\n        message: 'Too many requests, please upgrade your plan.'\n    });\n\n    return [rateLimiterMinute, rateLimiterMonth];\n}\n\n// export const subscriptionRateLimit = async (req : any, res : Response, next : NextFunction) : Promise<void> =>{\n\n// }\n\nexport const subscriptionMiddleware = async (req: any, res: Response, next: NextFunction): Promise<void | Response> => {\n    let user = req['user'];\n\n    let firstDayOfThisMonth = new Date(\n        new Date().getFullYear(),\n        new Date().getMonth(),\n        1\n    );\n\n    if (user) {\n        let subscription = await Subscription.findOne({\n            where: {\n                payment_status: subscription_payment_statuses.paid,\n                user_id: user.id,\n                end_date: {\n                    [Op.gte]: new Date()\n                }\n            }\n        });\n\n        if (subscription) {\n            let _plans = await plans()\n            let planData = _plans[subscription.plan];\n\n            let thirtyDaysAgo = new Date((new Date()).getTime() - (30 * 24 * 60 * 60 * 1000));\n            let minuteDaysAgo = new Date((new Date()).getTime() - (60 * 1000));\n            let totalRequestsInMonth = await Prompt.count({ where: { user_id: user.id, created_at: { [Op.between]: [thirtyDaysAgo, (new Date()).getTime()] } } });\n            let totalRequestsInMinute = await Prompt.count({ where: { user_id: user.id, created_at: { [Op.between]: [minuteDaysAgo, (new Date()).getTime()] } } });\n\n            if (totalRequestsInMinute >= planData.request_per_minute || totalRequestsInMonth >= planData.request_per_month) {\n                return res.status(StatusCodes.TOO_MANY_REQUESTS).json({ ok: false, message: messages.PROMPT_LIMIT_REACHED, status: StatusCodes.TOO_MANY_REQUESTS });\n            }\n\n            return next();\n\n            // let [rateLimiterMinute, rateLimiterMonth] = await getRateLimitersBySubscription(subscription.plan);\n            // return rateLimiterMinute(req, res, (err: any) => {\n            //     if (err) return;\n\n            //     return rateLimiterMonth(req, res, next);\n            // });\n        }\n\n\n        // let totalRequests = await Prompt.count({ where: { user_id: user.id } });\n\n        // if (totalRequests >= 10) {\n        //     return res.status(StatusCodes.TOO_MANY_REQUESTS).json({ ok: false, message: messages.PROMPT_LIMIT_REACHED, status: StatusCodes.TOO_MANY_REQUESTS });\n        // }\n\n        let totalRequests = await Prompt.count({ where : { user_id : user.id, created_at : { [Op.between] : [firstDayOfThisMonth, new Date()] } } });\n\n        if(totalRequests >= 5){\n            return res.status(StatusCodes.TOO_MANY_REQUESTS).json({ ok: false, message: messages.PROMPT_LIMIT_REACHED, status: StatusCodes.TOO_MANY_REQUESTS });\n        }\n\n        return next();\n    }\n\n    // const ip = Array.isArray(req.headers['x-forwarded-for']) \n    //         ? req.headers['x-forwarded-for'][0] \n    //         : req.headers['x-forwarded-for'] || req.socket.remoteAddress as string;\n\n    const forwarded = req.headers['x-forwarded-for'];\n\n    const ip = Array.isArray(forwarded)\n        ? forwarded[0]\n        : forwarded?.split(',')[0].trim() || req.socket.remoteAddress;\n\n\n    let totalRequests = await Prompt.count({ where: { ip, created_at : { [Op.between] : [firstDayOfThisMonth, new Date()] } } });\n\n    if (totalRequests >= 10) {\n        return res.status(StatusCodes.TOO_MANY_REQUESTS).json({ ok: false, message: messages.PROMPT_LIMIT_REACHED, status: StatusCodes.TOO_MANY_REQUESTS });\n    }\n\n    next();\n}",
    "exports": [
      "generatorRateLimit",
      "getRateLimitersBySubscription",
      "subscriptionMiddleware"
    ],
