    "content": "import { Table, Model, Column, DataType, CreatedAt, UpdatedAt, DeletedAt } from 'sequelize-typescript'\nimport { lengths, origination_sources, styles, tones } from '../utils/consts'\n\n@Table({ tableName : \"prompts\", paranoid : true })\nexport class Prompt extends Model{\n    @Column({ type : DataType.INTEGER, allowNull : false, primaryKey : true, autoIncrement : true })\n    public id!: number\n\n    @Column({ type : DataType.TEXT(\"long\"), allowNull : false })\n    public user_agent!: string\n\n    @Column({ type : DataType.TEXT(\"long\"), allowNull : false })\n    public ip!: string\n    \n    @Column({ type : DataType.TEXT, allowNull : false })\n    public prompt!: string\n\n    @Column({ type : DataType.TEXT, allowNull : true })\n    public options!: string\n\n    @Column({ type : DataType.TEXT, allowNull : true })\n    public response!: string\n\n    @Column({ type : DataType.TEXT, allowNull : true })\n    public text_context!: string\n\n    @Column({ type : DataType.TEXT, allowNull : true })\n    public file_context!: string\n\n    @Column({ type : DataType.TEXT, allowNull : true })\n    public intended_model!: string\n\n    @Column({ type : DataType.ENUM(...Object.values(origination_sources)), allowNull : true })\n    public source!: string\n\n    @Column({ type : DataType.ENUM(...Object.values(tones)), allowNull : true })\n    public tone!: string\n\n    @Column({ type : DataType.ENUM(...Object.values(styles)), allowNull : true })\n    public style!: string\n\n    @Column({ type : DataType.ENUM(...Object.values(lengths)), allowNull : true })\n    public length!: string\n\n    @Column({ type : DataType.INTEGER, allowNull : true })\n    public creativity!: string\n    \n    @CreatedAt\n    @Column({\n      type: DataType.DATE,\n      field: 'created_at',\n    })\n    public created_at!: Date;\n  \n    @UpdatedAt\n    @Column({\n      type: DataType.DATE,\n      field: 'updated_at',\n    })\n    public updated_at!: Date;\n  \n    @DeletedAt\n    @Column({\n      type: DataType.DATE,\n      field: 'deleted_at',\n    })\n    public deleted_at!: Date;\n}",
