    "content": "import express, { Router, Request, Response, NextFunction } from 'express';\nimport controller from '../controllers/auth.controller';\nimport { normalOrApiKey, verifyUnverifiedUser, verifyUser } from '../middlewares/auth';\nimport passport from 'passport';\nimport { googleAuthCallbackMiddleware } from '../middlewares/google';\nimport env from '../config/config';\n\nconst routes : Router = express.Router();\n\nroutes.post('/', async (req : Request, res : Response) : Promise<Response> =>{ return await controller.signup(req, res); });\nroutes.post('/login', async (req : Request, res : Response) : Promise<Response> =>{ return await controller.login(req, res); });\n\nroutes.get('/google', (req : Request, res : Response, next : NextFunction)=>{ passport.authenticate('google', { scope: ['email', 'profile'], session: false, state : JSON.stringify(req.query) })(req, res, next) } );\nroutes.get('/google/callback', \n    passport.authenticate('google', { session : false, failureRedirect: `${env.FRONTEND_LOGIN_URL}?error=google_auth_failed` }),\n    googleAuthCallbackMiddleware\n);\n\nroutes.post('/verify', verifyUnverifiedUser, async (req : any, res : Response) : Promise<Response> =>{ return await controller.verifyOtp(req, res); });\nroutes.post('/otp/resend', verifyUnverifiedUser, async (req : any, res : Response) : Promise<Response> =>{ return await controller.resendOtp(req, res); });\n\nroutes.get('/', normalOrApiKey, async (req : any, res : Response) : Promise<Response> =>{ return await controller.getUser(req, res); });\n\nroutes.use(verifyUser);\nroutes.put('/', async (req : any, res : Response) : Promise<Response> =>{ return await controller.updateUserDetails(req, res); });\nroutes.post('/api-key', async (req : any, res : Response) : Promise<Response> =>{ return await controller.generateApiKey(req, res); });\nroutes.post('/refresh', async (req : any, res : Response) : Promise<Response> =>{ return await controller.refreshToken(req, res); });\n\nexport default routes;",
