    "content": "import { User } from \"../models/User\";\nimport { CreateFolderType, EditFolderType, ListFoldersType } from \"../types/folder.types\";\nimport { ResponseType, SingleIdType } from \"../types/api.types\";\nimport { Folder } from \"../models/Folder\";\nimport { messages } from \"../utils/consts\";\nimport { StatusCodes } from \"http-status-codes\";\nimport { reversePagination } from \"../utils/validator\";\nimport { sequelize } from \"../config/database\";\n\nexport const createFolderService = async (payload: CreateFolderType, user: User): Promise<ResponseType> => {\n    const { title, description, parent_id } = payload;\n\n    let search = await Folder.findOne({ where: { title, user_id: user.id, parent_id } });\n\n    if (search) {\n        throw { ok: false, message: messages.FOLDER_ALREADY_EXISTS, status: StatusCodes.BAD_REQUEST }\n    }\n\n    let folder = await Folder.create({ title, description, parent_id, user_id: user.id });\n    let _folder = await Folder.findOne({\n        where: { id: folder.id }, include: [{\n            model: Folder,\n            as: 'parent',\n        }]\n    });\n\n    return { ok: true, message: messages.OK, status: StatusCodes.OK, body: { folder: _folder } };\n}\n\nexport const editFolderService = async (payload: EditFolderType, user: User): Promise<ResponseType> => {\n    const { id, title, description } = payload;\n\n    let folder = await Folder.findOne({ where: { id, user_id: user.id } });\n\n    if (!folder) {\n        throw { ok: false, message: messages.NOT_FOUND, status: StatusCodes.NOT_FOUND }\n    }\n\n    let _payload: any = {};\n\n    if (title) {\n        _payload.title = title;\n    }\n\n    if (description) {\n        _payload.description = description;\n    }\n\n    await Folder.update(_payload, { where: { id: folder.id } });\n\n    let _folder = await Folder.findOne({\n        where: { id: folder.id }, include: [{\n            model: Folder,\n            as: 'parent',\n        }]\n    });\n\n    return { ok: true, message: messages.OK, status: StatusCodes.OK, body: { folder: _folder } };\n}\n\nexport const deleteFolderService = async (payload: SingleIdType, user: User): Promise<ResponseType> => {\n    const { id } = payload;\n\n    await Folder.destroy({ where: { id, user_id: user.id } });\n\n    return { ok: true, message: messages.OK, status: StatusCodes.OK };\n}\n\nexport const listFoldersService = async (payload: ListFoldersType, user: User): Promise<ResponseType> => {\n    const { offset, limit, order, search, parent_id } = payload;\n\n    let where: any = { user_id: user.id };\n\n    if (search) {\n        where.title = { $like: `%${search}%` };\n    }\n\n    if (parent_id) {\n        where.parent_id = parent_id;\n    }\n\n    // Get folders with eager-loaded prompt_count using a subquery\n    let folders = await Folder.findAll({\n        where,\n        offset,\n        limit,\n        order: [['id', order]],\n        include: [\n            {\n                model: Folder,\n                as: 'parent',\n            },\n        ],\n        attributes: {\n            include: [\n                [\n                    sequelize.literal(`(\n                        SELECT COUNT(*)\n                        FROM \\`prompts\\` AS \\`Prompt\\`\n                        WHERE \\`Prompt\\`.\\`folder_id\\` = \\`Folder\\`.\\`id\\`\n                    )`),\n                    'prompt_count',\n                ],\n            ],\n        },\n    });\n\n    // Convert to plain objects if needed\n    folders = folders.map(folder => folder.toJSON());\n\n    let total_count = await Folder.count({ where })\n    let total_pages = Math.ceil(total_count / limit);\n\n    let reversed = reversePagination(limit, offset);\n\n    return { ok: true, message: messages.OK, status: StatusCodes.OK, body: { folders, limit: reversed.limit, offset: reversed.offset, order, search, total_count, total_pages } }\n\n}",
    "exports": [
      "createFolderService",
      "editFolderService",
      "deleteFolderService",
      "listFoldersService"
    ],
