    "content": "import { StatusCodes } from \"http-status-codes\";\nimport { Prompt } from \"../models/Prompt\";\nimport { ListWithPaginationType, ResponseType, SingleIdType } from \"../types/api.types\";\nimport { ListPromptsType, PromptType, SavePromptType } from \"../types/prompt.types\";\nimport { activity_types, lengths, messages } from \"../utils/consts\";\nimport { generateResponse } from './openai.service';\n// import { generateResponse } from './gemini.service';\nimport { log } from \"../utils/logger\";\nimport { User } from \"../models/User\";\nimport { literal, Op } from \"sequelize\";\nimport { reversePagination } from \"../utils/validator\";\nimport { Activity } from \"../models/Activity\";\nimport { Folder } from \"../models/Folder\";\n\nexport const savePromptService = async (payload : SavePromptType, user : User) : Promise<ResponseType> =>{\n    const { id, folder_id } = payload;\n\n    let folder = await Folder.findOne({ where : { id : folder_id, user_id : user.id } });\n    let prompt = await Prompt.findOne({ where : { id, user_id : user.id } });\n\n    if(!folder || !prompt){\n        throw { ok : false, message : messages.BAD_REQUEST, status : StatusCodes.BAD_REQUEST };\n    }\n\n    await Prompt.update({ folder_id }, { where : { id : prompt.id } });\n    \n    let _prompt = await Prompt.findOne({ where : { id : prompt.id } });\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { prompt : _prompt } }\n}\n\nexport const promptService = async (payload : PromptType, user?: User) : Promise<ResponseType> =>{\n    let dbPayload : any = {...payload };\n\n    if(dbPayload.file_context){\n        dbPayload.file_context = JSON.stringify(dbPayload.file_context);\n    }\n\n    let optionsPayload : any = {...dbPayload};\n\n    // if(!user){\n    //     optionsPayload = { length : lengths.short, creativity : 50 };\n        \n    //     delete dbPayload.options;\n    //     delete dbPayload.text_context;\n    //     delete dbPayload.file_context;\n    //     delete dbPayload.intended_model;\n    //     delete dbPayload.tone;\n    //     delete dbPayload.style;\n    //     delete dbPayload.length;\n    //     delete dbPayload.creativity;\n\n    //     dbPayload.creativity = 50;\n    //     dbPayload.length = lengths.short;\n\n    // }else{\n        delete optionsPayload.prompt;\n        delete optionsPayload.options;\n        delete optionsPayload.ip;\n        delete optionsPayload.user_agent;\n    // }\n\n    optionsPayload = JSON.stringify(optionsPayload);\n\n    let response : string | null;\n\n    try{\n        response = await generateResponse(dbPayload.prompt, optionsPayload, 0, dbPayload.intended_model);\n    }catch(error : any){\n        log(\"error\", { ...error });\n        throw { ok : false, message : messages.SERVER_ERROR, status : StatusCodes.INTERNAL_SERVER_ERROR };\n    }\n\n    if(!response){\n        throw { ok : false, message : messages.SERVER_ERROR, status : StatusCodes.INTERNAL_SERVER_ERROR };\n    }\n    \n    dbPayload.response = response;\n    dbPayload.user_id = user?.id || null;    \n\n    let prompt = await Prompt.create({...dbPayload});\n\n    if(dbPayload.user_id){\n        Activity.create({ title : \"New Prompt Generated\", type : activity_types.prompt_generated, user_id : dbPayload.user_id })\n    }\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { prompt } }\n}\n\nexport const listPromptsService = async (payload : ListPromptsType, user : User) : Promise<ResponseType> =>{\n    let { limit, offset, order, search, folder_id } = payload;\n\n    let where : any = {user_id : user.id};\n\n    if(search){\n        where.prompt = {\n            [Op.like] : `%${search}%`\n        }\n    }\n\n    if(folder_id){\n        let folder = await Folder.findOne({ where : { id : folder_id, user_id : user.id } });\n        if(folder){\n            where.folder_id = folder_id;\n        }\n    }\n\n    let prompts = await Prompt.findAll({ \n        attributes : [\n            [literal('SUBSTRING(response, 1, 100)'), 'response'],\n            \"id\", \"user_agent\", \"ip\", \"prompt\", \"created_at\", \"updated_at\", \"options\"\n        ], \n        where, \n        limit, \n        offset, \n        order: [['created_at', order]] \n    });\n    let total_count = await Prompt.count({ where });\n    let total_pages = Math.ceil(total_count / limit);\n\n    let reversed = reversePagination(limit, offset);\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { prompts, limit : reversed.limit, offset : reversed.offset, order, search, total_count, total_pages } }\n}\n\nexport const getPromptService = async (payload : SingleIdType, user : User) : Promise<ResponseType> =>{\n    const { id } = payload;\n\n    let prompt = await Prompt.findOne({ where : { id, user_id : user.id } });\n\n    if(!prompt){\n        throw { ok : false, message : messages.NOT_FOUND, status : StatusCodes.NOT_FOUND };\n    }\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { prompt } }\n}",
