    "content": "import stripe from 'stripe';\nimport env from '../config/config';\nimport { GeneratePaymentLinkPayload, GeneratePaymentLinkResponse } from '../types/stripe.types';\nimport { acceptable_currencies, messages, plans, subscription_payment_statuses, transaction_statuses, transaction_types, payment_providers, activity_types } from '../utils/consts';\nimport { log } from '../utils/logger';\nimport { User } from \"../models/User\";\nimport subscriptionSuccess from \"../utils/templates/sub-successful\";\nimport striptags from \"striptags\";\nimport { sendMail } from \"../utils/mail\";\nimport { Transaction } from \"../models/Transaction\";\nimport { Subscription } from \"../models/Subscription\";\nimport { sequelize } from \"../config/database\";\nimport { Activity } from \"../models/Activity\";\nimport { StatusCodes } from 'http-status-codes';\nimport { ResponseType } from \"../types/api.types\";\n\nconst stripeClient = new stripe(env.STRIPE_SECRET_KEY)\n\nexport const generatePaymentLinkStripe = async (payload: GeneratePaymentLinkPayload): Promise<GeneratePaymentLinkResponse> => {\n    let { amount, currency, description, email, product_id } = payload;\n\n    if (!currency) {\n        currency = acceptable_currencies.usd;\n    }\n\n    if (!description) {\n        description = 'Payment for subscription'\n    }\n\n    const session = await stripeClient.checkout.sessions.create({\n        line_items: [\n            {\n                price: product_id,\n                quantity: 1\n            }\n        ],\n        customer_email: email,\n        mode: \"subscription\",\n        success_url: env.POLAR_SUCCESS_URL\n    });\n\n    log(\"info\", { session });\n\n    if (!session.id || !session.url) {\n        throw messages.SERVER_ERROR\n    }\n\n    return { payment_id: session.id, payment_url: session.url }\n}\n\n\nexport const stripeReoccuringSubscriptionWebhookService = async (payload: any): Promise<ResponseType> => {\n    console.log(payload);\n\n    const { type } = payload;\n\n    if (type == \"invoice.paid\") {\n        let { data } = payload;\n        let { object } = data;\n        let { id, status, amount_paid } = object;\n        let product_id = object.lines.data[0].plan.id;\n        let amount = amount_paid / 100;\n        let email = object.customer_email;\n\n\n        let check = await Transaction.findOne({ where: { ref: id, type: transaction_types.credit, payment_provider: payment_providers.polar, status: transaction_statuses.completed } });\n\n        if (!check) {\n\n            if (status == \"paid\") {\n                let user = await User.findOne({ where: { email } });\n\n                if (user) {\n                    let _plans = await plans();\n                    let planData: any;\n                    let plan: string | null = null;\n                    let keys = Object.keys(_plans);\n\n                    let months: number = 0;\n\n                    for (let i = 0; i < keys.length; i++) {\n                        if (_plans[keys[i]].stripe_product_id == product_id) {\n                            planData = _plans[keys[i]];\n                            plan = keys[i];\n                            months = 1;\n                            break;\n                        }\n                        if (_plans[keys[i]].annual_stripe_id == product_id) {\n                            planData = _plans[keys[i]];\n                            plan = keys[i];\n                            months = 12;\n                            break;\n                        }\n                    }\n\n                    console.log(plan);\n\n                    if (plan) {\n                        let description = `Subscription for ${plan} by ${user.first_name}`;\n\n                        let discount_percent = 0;\n                        let discount = 0;\n\n                        if (months == 12) {\n                            // discount_percent = planData.annual_discount;\n                            // discount = ((amount / 100) * discount_percent) / 100;\n                        }\n\n\n                        let now = new Date();\n                        let subEndDate = new Date(now.getTime() + (Number(months) * 30 * 24 * 60 * 60 * 1000));\n\n                        await sequelize.transaction(async (transaction: any) => {\n                            await Subscription.create({\n                                plan,\n                                payment_status: subscription_payment_statuses.paid,\n                                user_id: user?.id as Number,\n                                months,\n                                start_date: now,\n                                end_date: subEndDate,\n                                subscription_id: id\n                            }, { transaction });\n                            await Transaction.create({\n                                amount: amount,\n                                type: transaction_types.credit,\n                                currency: acceptable_currencies.usd,\n                                payment_provider: payment_providers.stripe,\n                                ref: id,\n                                status: transaction_statuses.completed,\n                                description,\n                                user_id: user?.id as Number,\n                                discount,\n                                discount_percent\n                            }, { transaction })\n\n                            await Activity.create({ title: \"Subscription Paid via Stripe\", type: activity_types.subscription_successful, user_id: user?.id }, { transaction })\n                        });\n\n                        let html = subscriptionSuccess(user.first_name, plan);\n                        let text = striptags(html);\n\n                        try {\n                            await sendMail({ to: [user.email], subject: \"Subscription Successful\", text, html })\n                        } catch (error) {\n                            console.log(error);\n                        }\n                    }\n                }\n            }\n        }\n    }\n\n    return { ok: true, message: messages.OK, status: StatusCodes.OK };\n}",
