    "content": "import { SystemSetting } from \"../models/SystemSetting\";\nimport { messages, plans, system_setting_types } from \"../utils/consts\";\nimport { GetSettingType, ResponseType } from \"../types/api.types\";\nimport { StatusCodes } from \"http-status-codes\";\n\nexport const getSettingService = async (payload : GetSettingType) : Promise<ResponseType> =>{\n    const { type } = payload;\n\n    let setting = await SystemSetting.findOne({ where : { type } });\n\n    if(!setting){\n        throw { ok : false, message : messages.NOT_FOUND, status : StatusCodes.NOT_FOUND }\n    }\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { setting } }\n}\n\nexport const seedSettings = async () : Promise<void> =>{\n    let values = Object.values(system_setting_types);\n\n    for(let i = 0; i < values.length; i++){\n        let value = values[i];\n\n        let searchSetting = await SystemSetting.findOne({ where : { type : value } });\n\n        if(!searchSetting){\n            await SystemSetting.create({ type : value, value : JSON.stringify({}) });\n        }\n    }\n}",
