    "content": "import { User } from \"../models/User\";\nimport { ResponseType } from \"../types/api.types\";\nimport { ListTransactionsType } from \"../types/transaction.types\";\nimport { Transaction } from \"../models/Transaction\";\nimport { Op } from \"sequelize\";\nimport { reversePagination } from \"../utils/validator\";\nimport { messages } from \"../utils/consts\";\nimport { StatusCodes } from \"http-status-codes\";\n\nexport const listTransactionsService = async (payload : ListTransactionsType, user : User) : Promise<ResponseType> =>{\n    let { limit, offset, order, search, type, status, provider } = payload;\n\n    let where : any = { user_id : user.id };\n\n    if(type){\n        where.type = type\n    }\n\n    if(status){\n        where.status = status\n    }\n\n    if(search){\n        where.description = { [Op.like] : \"%\"+search+\"%\" }\n    }\n\n    if(provider){\n        where.payment_provider = provider;\n    }\n\n    let transactions = await Transaction.findAll({ where, limit, offset, order : [[\"id\", order]] });\n    let total_count = await Transaction.count({ where });\n    let total_pages = Math.ceil(total_count / limit);\n    let reversed = reversePagination(limit, offset);\n\n    return { ok : true, message : messages.OK, status : StatusCodes.OK, body : { transactions, limit : reversed.limit, offset : reversed.offset, order, search, total_count, total_pages } }\n}",
    "exports": [
      "listTransactionsService"
    ],
