    "content": "import { BAD_REQUEST } from \"http-status-codes\";\nimport { getSettingService } from \"../services/system.service\";\n\nexport const messages = {\n    DB_CONNECTED : \"Database has been connected successfully.\",\n    SERVER_FAILED_TO_START : \"Failed to start server\",\n    SERVER_STARTED : \"Server have been successfully started\",\n    PHONE_INUSE : \"The phone number you provided has been taken.\",\n    SERVER_ERROR : \"Sorry an internal server error occured, please try again.\",\n    ACCOUNT_CREATED : \"Account has been successfully created.\",\n    UNAUTHORIZED : \"Unauthorized request.\",\n    INVALID_OTP : \"The OTP you provided is invalid.\",\n    OTP_VERIFIED : \"OTP has successfully verified.\",\n    PHONE_NOT_VERIFIED : \"Phone number has been validated.\",\n    DETAILS_UPDATED : \"Account details have been successfully updated.\",\n    BAD_REQUEST : \"Bad request.\",\n    NOT_FOUND : \"Resource not found\",\n    OTP_RESENT : \"Otp has been successfully resent.\",\n    PIN_CREATED : \"Your pin has been successfully created.\",\n    LOGIN_SUCCESSFUL : \"Login was successful.\",\n    ID_ALREADY_VERIFIED : \"You have already verified your Id.\",\n    FAILED_TO_VERIFY_ID : \"Failed to verify your id, please check the information you provided\",\n    ID_VERIFIED : \"Id has been successfully verified.\",\n    ID_REQUIRED : \"Id front and back are required.\",\n    USER_NOT_FOUND : \"User not found.\",\n    USER_FOUND : \"User found.\",\n    USER_ALREADY_EXIST : \"User already exists.\",\n    EMAIL_TAKEN : \"The email address you provided has been taken\",\n    OK : \"Request Successful\",\n    ROUTE_NOT_FOUND : \"Route not found.\",\n    RESEND_TO_EARLY : \"You cannot send an otp at this time because the interval between now and your last otp is too low.\",\n    OTP_EXPIRED : \"The otp you provided has expired, please request for a new otp to continue.\",\n    FORBIDDEN : \"Access forbidden.\",\n    INVALID_LOGIN_CREDENTIALS : \"Invalid login credentials.\",\n    NETWORK_ERROR : \"Sorry a network error occured.\",\n    FOLDER_ALREADY_EXISTS : \"The folder you are trying to create already exists.\",\n    PROMPT_LIMIT_REACHED : \"Prompt limit has been reached, please upgrade your plan to continue.\"\n};\n\nexport enum otp_types{\n    verify_email=\"verify_email\",\n    reset_password=\"reset_password\"\n}\n\nexport enum otp_destination{\n    email=\"email\"\n}\n\nexport enum employment_statuses{\n    employed=\"Employed\",\n    self=\"Self Employed\",\n    unemployed=\"Unemployed\"\n}\n\nexport enum genders{\n    m=\"Male\",\n    f=\"Female\"\n}\n\nexport enum acceptable_currencies{\n    usd=\"usd\"\n}\n\nexport const plan_names = async () : Promise<any> =>{\n    return Object.keys(await plans());\n}\n\nexport enum subscription_payment_statuses{\n    pending=\"pending\",\n    paid=\"paid\",\n    failed=\"failed\"\n}\n\nexport const plans = async () : Promise<any> =>{\n    return JSON.parse((await getSettingService({ type : system_setting_types.subscription_plans })).body.setting.value)\n}\n\nexport enum transaction_types{\n    credit=\"credit\",\n    debit=\"debit\"\n}\n\nexport enum transaction_statuses{\n    pending=\"pending\",\n    completed=\"completed\",\n    failed=\"failed\"\n}\n\nexport enum payment_providers{\n    stripe=\"stripe\",\n    polar=\"polar\"\n}\n\nexport enum ordering_types{\n    asc=\"ASC\",\n    desc=\"DESC\"\n}\n\nexport enum api_key_types{\n    extension=\"extension\",\n    api=\"api\"\n}\n\n// export const discounts_on_annual_subscriptions = {\n//     [plan_names.pro] : 15,\n//     [plan_names.pro_plus] : 15\n// }\n\nexport enum activity_types{\n    login=\"login\",\n    prompt_generated=\"prompt_generated\",\n    subscription_successful=\"subscription_successful\",\n    subscription_initialized=\"subscription_initialized\"\n}\n\nexport enum tones{\n    professional=\"professional\",\n    friendly=\"friendly\",\n    casual=\"casual\",\n    creative=\"creative\",\n    technical=\"technical\"\n}\n\nexport enum styles{\n    detailed=\"detailed\",\n    concise=\"concise\",\n    structured=\"structured\",\n    step_by_step=\"step-by-step\",\n    conversational=\"conversational\"\n}\n\nexport enum lengths{\n    short=\"short\",\n    medium=\"medium\",\n    long=\"long\"\n}\n\nexport enum origination_sources{\n    web=\"web\",\n    chatgpt=\"chatgpt\"\n}\n\nexport enum intended_models{\n    default=\"default\",\n    veo3=\"veo3\",\n    sora=\"sora\",\n    midjourney=\"midjourney\",\n    dalle=\"dalle\",\n    runway=\"runway\",\n    pika=\"pika\"\n}\n\nexport const VIDEO_MODELS = [intended_models.veo3, intended_models.sora, intended_models.runway, intended_models.pika];\nexport const IMAGE_MODELS = [intended_models.midjourney, intended_models.dalle];\n\nexport enum polar_endpoints{\n    init_checkout=\"/checkouts/\",\n    cancel_subscription=\"/subscriptions/\"\n}\n\nexport enum log_levels{\n    info=\"info\",\n    warn=\"warn\",\n    error=\"error\"\n}\n\nexport enum request_methods{\n    post=\"POST\",\n    get=\"GET\",\n    delete=\"DELETE\"\n}\n\nexport enum system_setting_types{\n    dom_integration_payload=\"dom_integration_payload\",\n    subscription_plans=\"subscription_plans\"\n}",
