    "content": "import { mailer } from '../config/mail';\nimport env from '../config/config';\n\nexport const sendMail = async (details: { to: Array<string>, subject: string, text: string, html: string }) => {\n    let { to, subject, text, html } = details;\n    let readyTo = to.join(', ');\n    const send = await mailer.sendMail({\n        from: `\"Brim AI\" <${env.SMTP_USER}>`,\n        to : readyTo,\n        subject,\n        text,\n        html\n    });\n\n    try {\n        return send.messageId;\n    } catch (error) {\n        throw error;\n    }\n}\n\n// Pretending to send email\n// export const sendMail = async (details: { to: Array<string>, subject: string, text: string, html: string }) => {\n//     console.log(details);\n//     return \"hello-world\";\n// }\n\n",
    "exports": [
      "sendMail"
    ],
