    "content": "import { plan_names } from \"../consts\";\n\nexport default (name: string, plan_name: string) => {\n    return `<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <title>BrimAI</title>\n    <script\n      src=\"https://kit.fontawesome.com/13437b109b.js\"\n      crossorigin=\"anonymous\"\n    ></script>\n    <link href=\"https://fonts.cdnfonts.com/css/satoshi\" rel=\"stylesheet\" />\n    <style>\n      body {\n        background: #f0f0f0;\n        font-family: \"Satoshi\", sans-serif;\n      }\n\n      table {\n        border-spacing: 0;\n      }\n\n      td {\n        padding: 0;\n      }\n\n      img {\n        border: 0;\n      }\n\n      a {\n        color: inherit;\n      }\n\n      hr {\n        border: 0.5px solid rgba(196, 196, 196, 0.5);\n      }\n    </style>\n  </head>\n  <body>\n    <div\n      style=\"\n        width: 100%;\n        table-layout: fixed;\n        background: #f0f0f0;\n        padding-bottom: 60px;\n      \"\n    >\n      <table\n        width=\"100%\"\n        style=\"margin: 0 auto; width: 100%; max-width: 600px; border-spacing: 0\"\n      >\n      <tr>\n        <td align=\"center\">\n          <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\" style=\"margin: 20px 0%;\">\n            <tr>\n              <td align=\"center\" valign=\"middle\" style=\"padding-right: 5px;\">\n                <a href=\"https://dashboard.trybrim.app\"><img src=\"https://dashboard.trybrim.app/logo-black.png\"\n                    alt=\"BrimAI Logo\" width=\"35\" style=\"display: block;\" /></a>\n              </td>\n              <td align=\"center\" valign=\"middle\">\n                <h3 style=\"margin: 0; font-size: 18px; color: #000;\">\n                  <a href=\"https://dashboard.trybrim.app\" style=\"text-decoration: none; color: #000;\">Brim AI</a>\n                </h3>\n              </td>\n            </tr>\n          </table>\n        </td>\n      </tr>\n\n        <tr>\n          <td>\n            <table\n              width=\"100%\"\n              style=\"\n                background: #ffffff;\n                padding: 0.5rem 5% 2rem 5%;\n                margin: 0rem 0 2rem 0;\n              \"\n            >\n              <tr>\n                <td>\n                  <table width=\"100%\">\n                    <tr>\n                      <td>\n                        <h3\n                          style=\"\n                            text-align: Center;\n                            font-weight: 700;\n                            padding: 1rem 0;\n                          \"\n                        >\n                        Your BrimAI subscription is active 🎉\n                        </h3>\n                        <p>Hi ${name} ✌🏾,</p>\n                        <p style=\"margin: 1rem 0\">\n                          Thank you for subscribing to BrimAI. Your account is now upgraded to ${plan_name} and ready to go.\n                        </p>\n                        <p style=\"margin: 1rem 0\">\n                          Here’s what you can do with your subscription:\n\n                          <ul>\n                            <li>Access unlimited advanced prompt enhancements</li>\n                            \n                            <li>Save and organize unlimited prompts</li>\n                            \n                            <li>Get priority support and updates.</li>\n                          </ul>\n                        </p>\n                        <p style=\"margin: 1rem 0\">\n                          We’re committed to helping you get the most out of AI. If you have any questions, our support team is always ready to assist.\n                        </p>\n                        <p style=\"margin: 1rem 0\">\n                          We are excited that you chose the best prompt engineering experience.\n                        </p>\n\n                        <p style=\"margin: 1rem 0\">\n                          With love from the BrimAI team ❤️\n                        </p>\n\n                        <hr />\n                        <table width=\"100%\" style=\"margin-top: 20px;\">\n                        <tr>\n                          <td width=\"50%\" align=\"left\" valign=\"middle\"\n                            style=\"font-size: 14px; font-family: Arial, sans-serif;\">\n                            CONNECT WITH US\n                          </td>\n                          <td width=\"50%\" align=\"right\" valign=\"middle\">\n                            <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\n                              <tr>\n                                <td align=\"center\" valign=\"middle\" style=\"padding-left:15px;\">\n                                  <a href=\"https://x.com/trybrim\">\n                                    <img src=\"https://dashboard.trybrim.app/x-twitter.png\" width=\"24\" alt=\"Twitter\"\n                                      style=\"display:block;\">\n                                  </a>\n                                </td>\n                                <td align=\"center\" valign=\"middle\" style=\"padding-left:15px;\">\n                                  <a href=\"https://discord.gg/7x6nA6fU\">\n                                    <img src=\"https://dashboard.trybrim.app/discord.png\" width=\"24\" alt=\"Discord\"\n                                      style=\"display:block;\">\n                                  </a>\n                                </td>\n                                <td align=\"center\" valign=\"middle\" style=\"padding-left:15px;\">\n                                  <a href=\"https://linkedin.com/company/brimai\">\n                                    <img src=\"https://dashboard.trybrim.app/linkedin.png\" width=\"24\" alt=\"LinkedIn\"\n                                      style=\"display:block;\">\n                                  </a>\n                                </td>\n                              </tr>\n                            </table>\n                          </td>\n                        </tr>\n\n                      </table>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n      </table>\n    </div>\n  </body>\n</html>\n`;\n}",
