    "content": "import Joi from 'joi';\nimport { ObjectSchema } from 'joi';\nimport { SignupType, VerifyOtpType, LoginType, UpdateUserDetailsType } from '../../types/user.types';\nimport validator from '../validator';\nimport { api_key_types, employment_statuses, genders } from '../consts';\nimport { GenerateApiKeyType } from '../../types/api.types';\n\nexport const signupValidation = (body : any) : SignupType =>{\n    const schema : ObjectSchema = Joi.object({\n        first_name : Joi.string().required(),\n        last_name : Joi.string().required(),\n        email : Joi.string().email().required(),\n        password : Joi.string().min(8)\n    });\n\n    return validator(schema, body);\n}\n\nexport const verifyOtpValidation = (body : any) : VerifyOtpType =>{\n    const schema : ObjectSchema = Joi.object({\n        otp : Joi.string().required().max(6).min(6)\n    });\n\n    return validator(schema, body);\n}\n\nexport const loginValidation = (body : any) : LoginType =>{\n    const schema : ObjectSchema = Joi.object({\n        email : Joi.string().email().required(),\n        password : Joi.string().required()\n    });\n\n    return validator(schema, body);\n}\n\nexport const updateUserDetailsValidation = (body : any) : UpdateUserDetailsType =>{\n    const schema : ObjectSchema = Joi.object({\n        first_name : Joi.string().optional(),\n        last_name : Joi.string().optional(),\n        country : Joi.string().optional(),\n        dob : Joi.date().optional(),\n        gender : Joi.any().valid(...(Object.values(genders))).optional(),\n        hobbies : Joi.array().items(Joi.string().required()).optional(),\n        employment_status : Joi.any().valid(...(Object.values(employment_statuses))).optional(),\n        is_onboarding_complete : Joi.boolean().optional(),\n        interests : Joi.array().items(Joi.string().required()).optional(),\n        primary_focuses : Joi.array().items(Joi.string().required()).optional()\n    });\n\n    return validator(schema, body);\n}\n\nexport const generateApiKeyValidation = (body : any) : GenerateApiKeyType =>{\n    const schema : ObjectSchema = Joi.object({\n        type : Joi.any().valid(...Object.values(api_key_types)).required()\n    });\n\n    return validator(schema, body);\n}",
    "exports": [
      "signupValidation",
      "verifyOtpValidation",
      "loginValidation",
      "updateUserDetailsValidation",
      "generateApiKeyValidation"
    ],
