    "content": "import Joi from 'joi';\nimport { ObjectSchema } from 'joi';\nimport validator, { paginationValidation } from '../validator';\nimport { CreateFolderType, EditFolderType, ListFoldersType } from '../../types/folder.types';\nimport { ordering_types } from '../consts';\n\nexport const createFolderValidation = (body : any) : CreateFolderType =>{\n    const schema : ObjectSchema = Joi.object({\n        title : Joi.string().required(),\n        description : Joi.string().optional().allow(\"\"),\n        parent_id : Joi.number().optional().default(null)\n    });\n\n    return validator(schema, body);\n}\n\nexport const editFolderValidation = (body : any) : EditFolderType =>{\n    const schema : ObjectSchema = Joi.object({\n        title : Joi.string().optional(),\n        description : Joi.string().optional().allow(\"\"),\n        id : Joi.number().required()\n    });\n\n    return validator(schema, body);\n}\n\nexport const listFoldersValidation = (body : any) : ListFoldersType =>{\n    const schema : ObjectSchema = Joi.object({\n        offset : Joi.number().optional().default(0),\n        limit : Joi.number().optional().default(20),\n        order : Joi.any().valid(...Object.values(ordering_types)).optional().default('desc'),\n        search : Joi.string().optional().allow(\"\"),\n        parent_id : Joi.number().optional().default(null)\n    });\n    \n    let values = validator(schema, body);\n    return paginationValidation(values);\n}",
    "exports": [
      "createFolderValidation",
      "editFolderValidation",
      "listFoldersValidation"
    ],
