    "content": "import { ListPromptsType, PromptType, SavePromptType } from \"../../types/prompt.types\";\nimport Joi from 'joi';\nimport { ObjectSchema } from 'joi';\nimport validator, { paginationValidation } from '../validator';\nimport { ListWithPaginationType, SingleIdType } from \"../../types/api.types\";\nimport { lengths, messages, ordering_types, styles, tones } from \"../consts\";\n\nexport const promptValidation = (body: any): PromptType => {\n    const schema: ObjectSchema = Joi.object({\n        prompt: Joi.string().required().max(500).messages({\n            'string.max': 'Prompt cannot exceed 500 characters.',\n            'any.required': 'Prompt is required.'\n        }),\n        options: Joi.array().optional().items(Joi.string().required()),\n        ip: Joi.string().required(),\n        user_agent: Joi.string().required(),\n        text_context: Joi.string().optional(),\n        file_context: Joi.array().optional().items(Joi.string().required()),\n        intended_model: Joi.string().optional(),\n        tone: Joi.any().valid(...Object.values(tones)).optional(),\n        style: Joi.any().valid(...Object.values(styles)).optional(),\n        length: Joi.any().valid(...Object.values(lengths)).default(lengths.medium),\n        creativity: Joi.number().optional().default(50)\n    });\n\n    return validator(schema, body);\n}\n\nexport const listPromptsValidation = (body: any): ListPromptsType => {\n    const schema: ObjectSchema = Joi.object({\n        limit: Joi.number().optional().default(20),\n        offset: Joi.number().optional().default(0),\n        search: Joi.string().optional(),\n        order: Joi.any().valid(...(Object.values(ordering_types))).default(ordering_types.desc).optional(),\n        folder_id: Joi.number().optional().default(null)\n    });\n\n    let values = validator(schema, body);\n    return paginationValidation(values);\n}\n\nexport const listWithPaginationValidation = (body: any): ListWithPaginationType => {\n    const schema: ObjectSchema = Joi.object({\n        limit: Joi.number().optional().default(20),\n        offset: Joi.number().optional().default(0),\n        search: Joi.string().optional(),\n        order: Joi.any().valid(...(Object.values(ordering_types))).default(ordering_types.desc).optional()\n    });\n\n    let values = validator(schema, body);\n    return paginationValidation(values);\n}\n\nexport const singleIdValidation = (body: any): SingleIdType => {\n    const schema: ObjectSchema = Joi.object({\n        id: Joi.number().required()\n    });\n\n    return validator(schema, body);\n}\n\nexport const savePromptValidation = (body: any): SavePromptType => {\n    const schema: ObjectSchema = Joi.object({\n        id: Joi.number().required(),\n        folder_id: Joi.number().required()\n    });\n\n    return validator(schema, body);\n}",
