    "content": "import { SubscribePayloadType } from \"../../types/subscription.types\";\nimport Joi from 'joi';\nimport { ObjectSchema } from 'joi';\nimport validator from '../validator';\nimport { payment_providers, plan_names } from \"../consts\";\n\nexport const subscribeValidation = async (body : any) : Promise<SubscribePayloadType> =>{\n    const schema : ObjectSchema = Joi.object({\n        plan : Joi.any().valid(...Object.values(await plan_names())).required(),\n        months : Joi.number().valid(1, 12).optional().default(1),\n        provider : Joi.any().valid(...Object.values(payment_providers)).default(payment_providers.polar)\n    });\n\n    return validator(schema, body);\n}",
