    "content": "import { ListTransactionsType } from \"../../types/transaction.types\";\nimport Joi from 'joi';\nimport { ObjectSchema } from 'joi';\nimport validator from '../validator';\nimport { ordering_types, payment_providers, transaction_statuses, transaction_types } from \"../consts\";\n\nexport const listTransactionsValidation = (body : any) : ListTransactionsType =>{\n    const schema : ObjectSchema = Joi.object({\n        limit : Joi.number().optional().default(20),\n        offset : Joi.number().optional().default(0),\n        order : Joi.any().valid(...Object.values(ordering_types)).optional().default(ordering_types.desc),\n        search : Joi.string().optional(),\n        type : Joi.any().valid(...Object.values(transaction_types)).optional(),\n        status : Joi.any().valid(...Object.values(transaction_statuses)).optional(),\n        provider : Joi.any().valid(...Object.values(payment_providers)).optional()\n    });\n\n    return validator(schema, body);\n}\n",
